(window.webpackJsonp=window.webpackJsonp||[]).push([[87],{714:function(n,r){n.exports='\x3c!-- \r\ntitle: 02-单片机例程\r\nsort: \r\n--\x3e \r\n# 51例程\r\n\r\n## C基础\r\n\r\n- typedef old new ;\r\n\r\n  > 定义新名称\r\n  \r\n- #define new old\r\n\r\n  > 预处理命令\r\n  \r\n- \\_crol_(a,b)\r\n\r\n  > 包含在`intrins.h`文件中\r\n  >\r\n  > 循环左移：a是值,b是位数\r\n  >\r\n  > \\_cror_(a,b)：循环右移\r\n\r\n\r\n## Keil使用\r\n\r\n### debug\r\n\r\n1. 仿真\r\n\r\n  ![image-20200330184624331](https://gitee.com/nmdfzf404/Image-hosting/raw/master/20200711105841.png)\r\n\r\n2. 设置断点\r\n\r\n  ![image-20200328195141119](https://gitee.com/nmdfzf404/Image-hosting/raw/master/20200711105844.png)\r\n\r\n## 例程\r\n\r\n- LED闪烁\r\n\r\n  ```c\r\n  #include "reg51.h"\r\n    \r\n  sbit led = P0^0;\r\n  typedef unsigned char u8;\r\n  typedef unsigned int u16;\r\n    \r\n  void delay(u16 i)\t\t// 延时函数\r\n  {\r\n    while(i--);\r\n  }\r\n    \r\n  void main()\r\n  {\r\n    while(1)\r\n    {\r\n        led = 1;\r\n        delay(50000);\r\n            led = 0;\r\n        delay(50000);\r\n    }\r\n  }\r\n  ```\r\n  \r\n- LED流水灯\r\n\r\n  ```c\r\n  #include "reg51.h"\r\n  \r\n  typedef unsigned char u8;\r\n  typedef unsigned int u16;\r\n  \r\n  #define led P0\r\n  \r\n  void delay(u16 i)\r\n  {\r\n  \twhile(i--);\r\n  }\r\n  \r\n  void main()\r\n  {\r\n  \tu8 i = 0;\r\n  \tled = 0x01;\r\n  \tdelay(50000);\r\n  \twhile(1)\r\n  \t{\r\n  \t\tfor(i=0;i<7;i++)\r\n  \t\t{\r\n  \t\t\tled = (0x01<<i);\r\n  \t\t\t// led <<= 1;\t\t也可以这么写\r\n  \t\t\tdelay(50000);\r\n  \t\t}\r\n  \t\tfor(i=0;i<7;i++)\r\n  \t\t{\r\n  \t\t\tled = _cror_(led,1);\r\n  \t\t\tdelay(50000);\r\n  \t\t}\r\n  \t}\r\n  }\r\n  ```\r\n  \r\n- 蜂鸣器&继电器\r\n\r\n  ```c\r\n  #include "reg51.h"\r\n  #include "intrins.h"\r\n  \r\n  typedef unsigned char u8;\r\n  typedef unsigned int u16;\r\n  \r\n  sbit beep=P1^5;\r\n  \r\n  void delay(u16 i)\r\n  {\r\n  \twhile(i--);\r\n  }\r\n  \r\n  void main()\r\n  {\r\n  \twhile(1)\r\n  \t{\r\n  \t\tbeep=~beep;\t\t// 低电平时闭合\r\n  \t\tdelay(10000);\r\n  \t}\r\n  }\r\n  ```\r\n\r\n- 静态数码管\r\n\r\n  ```c\r\n  #include "reg51.h"\r\n  \r\n  typedef unsigned char u8;\r\n  typedef unsigned int u16;\r\n  \r\n  u8 code smgduan[]={0x3f,0x06,0x5b,0x4f,0x66,0x6d,0x7d,0x07,0x7f,\r\n  \t\t\t\t0x6f,0x77,0x7c,0x39,0x5e,0x79,0x71};\t// 共阴\r\n  // code将值存入data数据中\r\n  void delay(u16 i)\r\n  {\r\n  \twhile(i--);\r\n  }\r\n  \r\n  void main()\r\n  {\r\n  \tu8 i=0;\r\n  \tfor(i=0;i<16;i++)\r\n  \t{\r\n  \t\tP0=~smgduan[i];\r\n  \t\tdelay(100000);\r\n  \t}\r\n  }\r\n  ```\r\n\r\n- 动态数码管\r\n\r\n  ```c\r\n  #include "reg51.h"\r\n  \r\n  typedef unsigned char u8;\r\n  typedef unsigned int u16;\r\n  \r\n  sbit LSA=P2^2;\r\n  sbit LSB=P2^3;\r\n  sbit LSC=P2^4;\r\n  \r\n  u8 code smgduan[]={0x3f,0x06,0x5b,0x4f,0x66,0x6d,0x7d,0x07,0x7f,\r\n  \t\t\t\t0x6f,0x77,0x7c,0x39,0x5e,0x79,0x71};\r\n  \r\n  void delay(u16 i)\r\n  {\r\n  \twhile(i--);\r\n  }\r\n  \r\n  void DigDisplay()\r\n  {\r\n  \tu8 i;\r\n  \tfor(i=0;i<8;i++)\r\n  \t{\r\n  \t\tswitch(i)\r\n  \t\t{\r\n  \t\t\tcase 0:\r\n  \t\t\t\tLSA=0;LSB=0;LSC=0;break;\r\n  \t\t\tcase 1:\r\n  \t\t\t\tLSA=1;LSB=0;LSC=0;break;\r\n  \t\t\tcase 2:\r\n  \t\t\t\tLSA=0;LSB=1;LSC=0;break;\r\n  \t\t\tcase 3:\r\n  \t\t\t\tLSA=1;LSB=1;LSC=0;break;\r\n  \t\t\tcase 4:\r\n  \t\t\t\tLSA=0;LSB=0;LSC=1;break;\r\n  \t\t\tcase 5:\r\n  \t\t\t\tLSA=1;LSB=0;LSC=1;break;\r\n  \t\t\tcase 6:\r\n  \t\t\t\tLSA=0;LSB=1;LSC=1;break;\r\n  \t\t\tcase 7:\r\n  \t\t\t\tLSA=1;LSB=1;LSC=1;break;\r\n  \t\t}\r\n  \t\tP0=smgduan[i];\r\n  \t\tdelay(100);\r\n  \t\tP0=0x00;\t\t// 清零\r\n  \t}\r\n  }\r\n  \r\n  void main()\r\n  {\r\n  \twhile(1)\r\n  \t{\r\n  \t\tDigDisplay();\r\n  \t}\r\n  }\r\n  ```\r\n  \r\n- 独立按键\r\n\r\n  ```c\r\n  #include "reg51.h"\r\n  \r\n  \r\n  typedef unsigned char u8;\r\n  typedef unsigned int u16;\r\n  \r\n  u8 code smgduan[]={0x3f,0x06,0x5b,0x4f,0x66,0x6d,0x7d,0x07,0x7f,\r\n  \t\t\t\t0x6f,0x77,0x7c,0x39,0x5e,0x79,0x71};\r\n  \r\n  void delay(u16 i)\r\n  {\r\n  \twhile(i--);\r\n  }\r\n  \r\n  u8 keypros()\r\n  {\r\n  \twhile(1)\r\n  \t{\r\n  \t\tif(P1<0xff)\r\n  \t\t{\r\n  \t\t\tdelay(1000);\r\n  \t\t\tswitch(P1)\r\n  \t\t\t{\r\n  \t\t\t\tcase(0x7f):return 7;break;\r\n  \t\t\t\tcase(0xbf):return 6;break;\r\n  \t\t\t\tcase(0xdf):return 5;break;\r\n  \t\t\t\tcase(0xef):return 4;break;\r\n  \t\t\t\tcase(0xf7):return 3;break;\r\n  \t\t\t\tcase(0xfb):return 2;break;\r\n  \t\t\t\tcase(0xfd):return 1;break;\r\n  \t\t\t\tcase(0xfe):return 0;break;\r\n  \t\t\t}\t\t\t\t\r\n  \t\t}\r\n  \t}\t\r\n  \r\n  }\t\r\n  \r\n  void smg(u8 key)\r\n  {\r\n  \tP0=~smgduan[key];\r\n  }\r\n  \r\n  void main()\r\n  {\r\n  \twhile(1)\r\n  \t\tsmg(keypros());\r\n  }\r\n  ```\r\n  \r\n- 矩阵按键\r\n\r\n  ```c\r\n  #include "reg51.h"\r\n  \r\n  \r\n  typedef unsigned char u8;\r\n  typedef unsigned int u16;\r\n  \r\n  #define GPIO_KEY P1\r\n  #define GPIO_DIG P0\r\n  \r\n  u8 code smgduan[]={0x3f,0x06,0x5b,0x4f,0x66,0x6d,0x7d,0x07,0x7f,\r\n  \t\t\t\t0x6f,0x77,0x7c,0x39,0x5e,0x79,0x71};\r\n  u8 KeyValue;\r\n  \r\n  void delay(u16 i)\r\n  {\r\n  \twhile(i--);\r\n  }\r\n  \r\n  void KeyDown()\r\n  {\r\n  \tchar exit;\r\n  \tGPIO_KEY = 0x0f;\r\n  \tif(GPIO_KEY!=0x0f)\r\n  \t{\r\n  \t\tdelay(1000);\r\n  \t\tif(GPIO_KEY!=0x0f)\r\n  \t\t{\r\n  \t\t\tswitch(GPIO_KEY)\r\n  \t\t\t{\r\n  \t\t\t\tcase(0x07): KeyValue=3;break;\r\n  \t\t\t\tcase(0x0b): KeyValue=2;break;\r\n  \t\t\t\tcase(0x0d): KeyValue=1;break;\r\n  \t\t\t\tcase(0x0e): KeyValue=0;break;\r\n  \t\t\t}\r\n  \t\t\tGPIO_KEY = 0xf0;\r\n  \t\t\tswitch(GPIO_KEY)\r\n  \t\t\t{\r\n  \t\t\t\tcase(0x70): KeyValue+=12;break;\r\n  \t\t\t\tcase(0xb0): KeyValue+=8;break;\r\n  \t\t\t\tcase(0xd0): KeyValue+=4;break;\r\n  \t\t\t\tcase(0xe0): KeyValue=KeyValue;break;\r\n  \t\t\t}\r\n  \t\t\twhile((exit<50)&&(GPIO_KEY!=0xf0))\r\n  \t\t\t{\r\n  \t\t\t\tdelay(1000);\r\n  \t\t\t\texit++;\r\n  \t\t\t}\r\n  \t\t}\r\n  \t}\r\n  }\t\r\n  \r\n  \r\n  void main()\r\n  {\r\n  \twhile(1)\r\n  \t{\r\n  \t\tKeyDown();\r\n  \t\tGPIO_DIG = ~smgduan[KeyValue];\r\n  \t}\r\n  \t\t\r\n  }\r\n  ```\r\n\r\n\r\n## 显示\r\n\r\n- 16*16点阵\r\n\r\n  ```c\r\n  #include "reg51.h"\r\n  // _nop_();原型\r\n  #include "intrins.h"\r\n  \r\n  typedef unsigned char u8;\r\n  typedef unsigned int u16;\r\n  \r\n  sbit SRCLK = P3^6;\r\n  sbit RCLK = P3^5;\r\n  sbit SER = P3^4;\r\n  \r\n  u8 code ledwei[]=\r\n  {\r\n  0x01,0x02,0x04,0x08,0x10,0x20,0x40,0x80,0x00,0x00,0x00,0x00,0x00,0x00,0x00,0x00,\r\n  0x80,0x00,0x00,0x00,0x00,0x00,0x00,0x00,0x00,0x01,0x02,0x04,0x08,0x10,0x20,0x40,\r\n  };\r\n  \r\n  u8 code ledduan1[]=\r\n  {\r\n  /*--  文字:  █  --*/\r\n  /*--  宋体12;  此字体下对应的点阵为：宽x高=16x16   --*/\r\n  0xFF,0xFF,0xFF,0xFF,0xFF,0xFF,0xFF,0xFF,0xFF,0xFF,0xFF,0xFF,0xFF,0xFF,0xFF,0xFF,\r\n  0xFF,0xFF,0xFF,0xFF,0xFF,0xFF,0xFF,0xFF,0xFF,0xFF,0xFF,0xFF,0xFF,0xFF,0xFF,0xFF,\r\n  };\r\n  \r\n  void delay(u16 i)\r\n  {\r\n      while(i--);\r\n  }\r\n  \r\n  void Send595(u8 dat1, u8 dat2, u8 dat3, u8 dat4)\r\n  {\r\n  \tu8 a;\r\n  \tSRCLK=1;\r\n  \tRCLK=1;\r\n  \tfor(a=0;a<8;a++)\r\n  \t{\r\n  \t\tSER = dat1>>7;\r\n  \t\tdat1<<=1;\r\n  \t\t\r\n  \t\tSRCLK=0;\r\n  \t\t_nop_();\r\n  \t\t_nop_();\r\n          SRCLK=1;\r\n  \t}\r\n  \tfor(a=0;a<8;a++)\r\n  \t{\r\n  \t\tSER = dat2>>7;\r\n  \t\tdat2<<=1;\r\n  \t\t\r\n  \t\tSRCLK=0;\r\n  \t\t_nop_();\r\n  \t\t_nop_();\r\n          SRCLK=1;\r\n  \t}\r\n  \tfor(a=0;a<8;a++)\r\n  \t{\r\n  \t\tSER = dat3>>7;\r\n  \t\tdat3<<=1;\r\n  \t\t\r\n  \t\tSRCLK=0;\r\n  \t\t_nop_();\r\n  \t\t_nop_();\r\n          SRCLK=1;\r\n  \t}\r\n  \tfor(a=0;a<8;a++)\r\n  \t{\r\n  \t\tSER = dat4>>7;\r\n  \t\tdat4<<=1;\r\n  \t\t\r\n  \t\tSRCLK=0;\r\n  \t\t_nop_();\r\n  \t\t_nop_();\r\n          SRCLK=1;\r\n  \t}\r\n  \tRCLK=0;\r\n  \t_nop_();\r\n  \t_nop_();\r\n  \tRCLK=1;\r\n  }\r\n  \r\n  int main()\r\n  {\r\n      u8 i;\r\n      while(1)\r\n      {\r\n          for(i=0;i<16;i++)\r\n          {\r\n              Send595(~ledwei[i+16],~ledwei[i],ledduan1[16+i],ledduan1[1]);\r\n              delay(10);\r\n          }\r\n      }\r\n  }\r\n  ```\r\n\r\n\r\n- 步进电机\r\n\r\n  ```c\r\n  #include "reg51.h"\r\n  \r\n  typedef unsigned char u8;\r\n  typedef unsigned int u16;\r\n  \r\n  sbit motoA=P1^0;\r\n  sbit motoB=P1^1;\r\n  sbit motoC=P1^2;\r\n  sbit motoD=P1^3;\r\n  \r\n  #define SPEED 200\r\n  \r\n  void delay(u16 i)\r\n  {\r\n      while(i--);\r\n  }\r\n  \r\n  void main()\r\n  {\r\n  \tP1=0x00;\r\n      while(1)\r\n  \t{\r\n  \t\tmotoA=1;\r\n  \t\tmotoB=0;\r\n  \t\tmotoC=0;\r\n  \t\tmotoD=0;\r\n  \t\t\r\n  \t\tdelay(SPEED);\r\n  \t\t\r\n  \t\tmotoA=0;\r\n  \t\tmotoB=1;\r\n  \t\tmotoC=0;\r\n  \t\tmotoD=0;\r\n  \t\t\r\n  \t\tdelay(SPEED);\r\n  \r\n  \t\tmotoA=0;\r\n  \t\tmotoB=0;\r\n  \t\tmotoC=1;\r\n  \t\tmotoD=0;\r\n  \t\t\r\n  \t\tdelay(SPEED);\r\n  \t\t\r\n  \t\tmotoA=0;\r\n  \t\tmotoB=0;\r\n  \t\tmotoC=0;\r\n  \t\tmotoD=1;\r\n  \t\t\r\n  \t\tdelay(SPEED);\r\n  \t}\r\n  }\r\n  ```\r\n\r\n  '}}]);